parts.text:
{
  "prototype_name": "Castle_Clashers_Playable",
  "implementation_summary": "A 2D artillery game using Canvas 2D. Players drag on their castle to aim a trajectory line and release to fire projectiles at the enemy castle. Simple ballistic physics and AABB rectangle collisions are used to detect hits, reducing castle health. The enemy auto-fires on a timer. The game ends when either castle's health reaches zero, triggering an end card.",
  "screen": {
    "orientation": "portrait",
    "logical_width": 360,
    "logical_height": 640,
    "responsive_strategy": "scale-to-fit-center"
  },
  "gameplay": {
    "objective": "Destroy the enemy red castle before your blue castle is destroyed.",
    "primary_interaction": "Drag to aim (showing a dotted trajectory line) and release to fire a projectile.",
    "win_condition": "Enemy castle health reaches 0.",
    "loss_or_timeout_condition": "Player castle health reaches 0 or 30 seconds elapse.",
    "session_length_seconds": 30
  },
  "entities": [
    {
      "id": "background",
      "role": "environment",
      "asset": "Background.png",
      "behavior": "Static background image scaled to cover the canvas.",
      "priority": "must"
    },
    {
      "id": "player_castle",
      "role": "player_base",
      "asset": "Blue Castle.png",
      "behavior": "Static on the left side. Has a health bar above it. Takes damage when hit by enemy projectiles.",
      "priority": "must"
    },
    {
      "id": "enemy_castle",
      "role": "enemy_base",
      "asset": "Red Castle.png",
      "behavior": "Static on the right side. Has a health bar above it. Takes damage when hit by player projectiles.",
      "priority": "must"
    },
    {
      "id": "player_weapon",
      "role": "launcher",
      "asset": "Weapon_1.png",
      "behavior": "Positioned on the player castle. Rotates based on drag angle.",
      "priority": "should"
    },
    {
      "id": "enemy_weapon",
      "role": "launcher",
      "asset": "Weapon_2.png",
      "behavior": "Positioned on the enemy castle. Auto-aims and fires on a timer.",
      "priority": "should"
    },
    {
      "id": "player_projectile",
      "role": "projectile",
      "asset": "Projectile_1.png",
      "behavior": "Spawns on release. Follows a ballistic arc with gravity. Collides with enemy castle.",
      "priority": "must"
    },
    {
      "id": "enemy_projectile",
      "role": "projectile",
      "asset": "Projectile_2.png",
      "behavior": "Spawns on enemy timer. Follows a ballistic arc. Collides with player castle.",
      "priority": "must"
    },
    {
      "id": "character_cyclop",
      "role": "visual_flair",
      "asset": null,
      "behavior": "PSB format unsupported. Omitted for V1.",
      "priority": "could"
    }
  ],
  "asset_plan": [
    {
      "asset_path": "Background.png",
      "use": "Background environment",
      "processing": "Scale to fit height, center horizontally",
      "required": true
    },
    {
      "asset_path": "Blue Castle.png",
      "use": "Player base",
      "processing": "Scale down to fit left side of screen",
      "required": true
    },
    {
      "asset_path": "Red Castle.png",
      "use": "Enemy base",
      "processing": "Scale down to fit right side of screen",
      "required": true
    },
    {
      "asset_path": "Weapon_1.png",
      "use": "Player launcher visual",
      "processing": "Anchor at center-left for rotation",
      "required": true
    },
    {
      "asset_path": "Weapon_2.png",
      "use": "Enemy launcher visual",
      "processing": "Anchor at center-right for rotation",
      "required": true
    },
    {
      "asset_path": "Projectile_1.png",
      "use": "Player ammo",
      "processing": "Scale down, rotate along velocity vector during flight",
      "required": true
    },
    {
      "asset_path": "Projectile_2.png",
      "use": "Enemy ammo",
      "processing": "Scale down, rotate along velocity vector during flight",
      "required": true
    },
    {
      "asset_path": "Music.ogg",
      "use": "Background music",
      "processing": "Loop, start on first interaction",
      "required": false
    },
    {
      "asset_path": "Sfx.wav",
      "use": "Explosion/Hit sound",
      "processing": "Play on projectile collision",
      "required": false
    }
  ],
  "interaction_flow": [
    {
      "step": 1,
      "player_action": "Touch and drag anywhere on the left side of the screen",
      "system_response": "Draws a dotted trajectory arc from the player castle based on drag vector. Rotates player weapon."
    },
    {
      "step": 2,
      "player_action": "Release touch",
      "system_response": "Fires player_projectile along the calculated arc. Hides trajectory line."
    },
    {
      "step": 3,
      "player_action": "Wait",
      "system_response": "Projectile travels. If it intersects enemy_castle bounds, trigger hit VFX, play Sfx, reduce enemy health bar."
    },
    {
      "step": 4,
      "player_action": "None (Enemy Turn)",
      "system_response": "Enemy auto-fires a projectile towards the player castle after a set interval."
    },
    {
      "step": 5,
      "player_action": "None (Game Over)",
      "system_response": "When a health bar reaches 0, show End Card with 'Play Now' CTA."
    }
  ],
  "parameters": [
    {
      "name": "player_damage",
      "type": "number",
      "default": 34,
      "variation_range": "20-50",
      "gameplay_effect": "Determines how many hits it takes to destroy the enemy castle (default 3 hits for 100 health)."
    },
    {
      "name": "enemy_damage",
      "type": "number",
      "default": 20,
      "variation_range": "10-30",
      "gameplay_effect": "Determines how quickly the player loses if they miss."
    },
    {
      "name": "gravity",
      "type": "number",
      "default": 900,
      "variation_range": "500-1500",
      "gameplay_effect": "Affects the arc of the projectiles and aiming difficulty."
    },
    {
      "name": "enemy_fire_rate_ms",
      "type": "number",
      "default": 3000,
      "variation_range": "2000-5000",
      "gameplay_effect": "Controls the pressure on the player to aim and fire quickly."
    }
  ],
  "acceptance_criteria": [
    "Game renders entirely in a single HTML file using Canvas 2D.",
    "Dragging produces a visible dotted trajectory line.",
    "Releasing fires a projectile that follows the trajectory.",
    "Projectiles colliding with castles reduce the respective health bar.",
    "Enemy fires back automatically on a timer.",
    "End card displays when either castle's health reaches 0."
  ],
  "non_goals_v1": [
    "Complex block-by-block physics destruction of the castles.",
    "Multiple character selections or PSB character animations.",
    "Moving castles (tank treads will remain static).",
    "Multiple projectile types for the player (sticking to one for simplicity)."
  ]
}
